import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface QuoteData {
  quote: {
    text: string;
    author: string;
    category: string;
  };
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const data = response.data as QuoteData;
  const meta = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 280, maxWidth: 380, bgcolor: '#FFFFFF', borderColor: meta.primaryColor }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: meta.primaryColor }}>
              Quote of the Day
            </Typography>
            <Typography variant="body1" color="text.secondary" sx={{ mt: 1 }}>
              "{data.quote.text}"
            </Typography>
            <Typography variant="body2" sx={{ color: meta.primaryColor, mt: 1, fontWeight: 500 }}>
              - {data.quote.author}
            </Typography>
          </Box>
          <Stack direction="row" spacing={0.5}>
            <Chip label={data.quote.category} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: meta.accentColor, color: '#FFFFFF' }} />
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
